INSERT OR REPLACE INTO questions (id, criteria_id, setup_id, question_text, testset, notes, autoanswer, computer_evaluable, expected_answer_json, evaluation_type, answer_schema_json) VALUES (301, 'richtigkeit', 'setup_flowmap', 'Bearbeite die folgende komplexe Aufgabe. Erledige alle sieben Teilaufgaben.

Thema: Antibiotika und Grippe

1. Bearbeite die konkrete Situation: Ein Lernzettel behauptet, Antibiotika seien die beste Behandlung gegen Grippeviren.
2. Schreibe passend fuer diese Zielgruppe: 9. Klasse Biologie.
3. Halte das Ausgabeformat strikt ein: exakt valides JSON mit keys urteil, korrektur, begruendung, beispiel, warnung.
4. Behandle die typische Falle: Der Text vermischt Viren, Bakterien und Medikamente.
5. Beachte diese Begrenzung: Vermeide Heilversprechen und Diagnose.
6. Fuege eine kurze Kontrolle, Grenze, Unsicherheit oder Plausibilitaetspruefung ein.
7. Schliesse mit einem klaren Fazit oder einer direkt nutzbaren Empfehlung.

Die Endantwort muss zeigen, dass die sieben Punkte zusammen verarbeitet wurden, nicht nur einzeln aufgelistet.', 'flowmap_parallel7_questions', 'richtigkeit flowmap_parallel7_questions-1; set7; seven-part complex task for Flowmap', 1, 0, NULL, 'llm_checkpoint', NULL);
INSERT OR REPLACE INTO questions (id, criteria_id, setup_id, question_text, testset, notes, autoanswer, computer_evaluable, expected_answer_json, evaluation_type, answer_schema_json) VALUES (302, 'richtigkeit', 'setup_flowmap', 'Bearbeite die folgende komplexe Aufgabe. Erledige alle sieben Teilaufgaben.

Thema: Schweizer Hauptstadt

1. Bearbeite die konkrete Situation: Ein Text nennt Zuerich die Hauptstadt der Schweiz und begruendet das mit Wirtschaftskraft.
2. Schreibe passend fuer diese Zielgruppe: Maturaarbeit Politik.
3. Halte das Ausgabeformat strikt ein: CSV mit Header Aussage;Bewertung;Korrektur;Begruendung und genau 3 Datenzeilen.
4. Behandle die typische Falle: Bern/Bundesstadt muss sauber von groesster Stadt unterschieden werden.
5. Beachte diese Begrenzung: Keine unklare Formulierung wie irgendwie Hauptstadt.
6. Fuege eine kurze Kontrolle, Grenze, Unsicherheit oder Plausibilitaetspruefung ein.
7. Schliesse mit einem klaren Fazit oder einer direkt nutzbaren Empfehlung.

Die Endantwort muss zeigen, dass die sieben Punkte zusammen verarbeitet wurden, nicht nur einzeln aufgelistet.', 'flowmap_parallel7_questions', 'richtigkeit flowmap_parallel7_questions-2; set7; seven-part complex task for Flowmap', 1, 0, NULL, 'llm_checkpoint', NULL);
