INSERT OR REPLACE INTO questions (id, criteria_id, setup_id, question_text, testset, notes, autoanswer, computer_evaluable, expected_answer_json, evaluation_type, answer_schema_json) VALUES (441, 'rueckfragefaehigkeit', 'setup_flowreview', 'Bearbeite die folgende komplexe Aufgabe. Erledige alle sieben Teilaufgaben.

Thema: Workshop planen

1. Stelle genau sieben notwendige Rueckfragen.
2. Decke Ziel, Kontext und fehlende Daten ab.
3. Frage nach Constraints wie Zeit, Budget, Format oder Zielgruppe, wenn passend.
4. Erklaere kurz, warum die wichtigsten Rueckfragen noetig sind.
5. Gib noch keine endgueltige Loesung.
