INSERT OR REPLACE INTO questions (id, criteria_id, setup_id, question_text, testset, notes, autoanswer, computer_evaluable, expected_answer_json, evaluation_type, answer_schema_json) VALUES (751, 'richtigkeit', NULL, 'Computer-evaluable richtigkeit task #1.
Consider these facts: A shop gives 15 percent discount on 80 CHF. Final price is 68 CHF.
Return ONLY valid JSON. No markdown, no explanation, no extra keys.
The JSON keys must be exactly: ["answer","value","error_count"].
Use strings, numbers, booleans/arrays exactly as required by the facts.', 'ce_main_structured_questions', 'richtigkeit computer-evaluable json_exact #1; usable with Direct, Flowreview, Flowmap, and Prompt-Optimierung', 0, 1, '{"answer":"yes","value":68,"error_count":0}', 'json_exact', NULL);
INSERT OR REPLACE INTO questions (id, criteria_id, setup_id, question_text, testset, notes, autoanswer, computer_evaluable, expected_answer_json, evaluation_type, answer_schema_json) VALUES (752, 'richtigkeit', NULL, 'Computer-evaluable richtigkeit task #2.
Consider these facts: A train travels 120 km in 1.5 hours. Average speed is 90 km/h.
Return ONLY valid JSON. No markdown, no explanation, no extra keys.
